svg.script:
(() => {
  const VIEW_W = 374;
const TOP_CHAIN = ["A", "L", "C", "D", "E", "R", "G"];
const RAW_ANCHORS = {
    A: { x: 65, y: 153 }, L: { x: 137.77, y: 162.56 },
    C: { x: 171.37, y: 154.02 }, D: { x: 189.69, y: 147.65 },
    E: { x: 210.43, y: 157.48 }, R: { x: 240.66, y: 162.63 },
    G: { x: 309, y: 153 }
  };
const FACE_BASE = {
    cheekD: "M65 153 C97 159 136 168 172 154 C181 150 193 147 202 154 C238 168 277 159 309 153 C331 178 336 221 303 246 C270 268 104 268 71 246 C38 221 43 178 65 153Z",
    headCapD: "M64 153 C64 88 116 48 187 48 C258 48 310 88 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z",
    leftCreaseD: "M62 238 C70 250 84 256 100 256",
    rightCreaseD: "M312 238 C304 250 290 256 274 256"
  };
const RIGHT_HEAD_CAP_D = "M64 153 C66.12 89.55 117.55 49.81 187 48 C267.24 48 328.48 88 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z";
const LEFT_HEAD_CAP_D = "M64 153 C45.52 88 106.76 48 187 48 C256.45 49.81 307.88 89.55 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z";
const FRONT_TAIL = [
    [331, 178, 336, 221, 303, 246],
    [270, 268, 104, 268, 71, 246],
    [38, 221, 43, 178, 65, 153]
  ];
const LEFT_TAIL = [
    [320.06, 180.73, 321.87, 218.27, 303, 246],
    [270, 268, 104, 268, 71, 246],
    [35.12, 221, 40.60, 178, 65, 153]
  ];
const RIGHT_TAIL = [
    [333.40, 178.00, 338.88, 221.00, 303, 246],
    [270, 268, 104, 268, 71, 246],
    [52.13, 218.27, 53.94, 180.73, 65, 153]
  ];
const PITCH_UP = { axis: -25.5, lower: 3.6, faceDy: -21.5, faceSy: .93, blushDy: -22.41, earDy: 12, tuftDy: 12 };
const PITCH_DOWN = { axis: 26, lower: -7.9, faceDy: 24.5, faceSy: 1, blushDy: 24.5, earDy: -10, tuftDy: -2 };
const BODY_ORIGIN = { x: 187, y: 322 };
const TAIL_ORIGIN = { x: 187, y: 356 };
const TIE_BLADE_PIVOT = { x: 34, y: 24 };
const DEFAULTS = {
    showReference: true,
    showOriginalHands: false,
    showBones: false,
    bodyTransparent: false,
    darkStage: true,
    applyErrorFace: true,
    applyFaceLook: true,
    playWobble: false,
    decorEnabled: true,
    panicLinesEnabled: true,
    chestErrorEnabled: true,
    decorPulseEnabled: true,
    layerMode: "under-face",
    faceYaw: 0,
    wobbleAngle: 55,
    facePitch: 0,
    wobbleSeconds: 1.8,
    wobbleSpeed: 6.5,
    faceSmoothing: .025,
    referenceOpacity: 1,
    bodyMotionEnabled: true,
    tieMotionEnabled: true,
    handMotionEnabled: true,
    bodyFollowX: 2,
    bodyLean: .8,
    bodySink: 1.2,
    bodySquash: .012,
    tieSwing: 16,
    tieLag: .18,
    tieFlutter: 4,
    handRootSwing: .9,
    handTremble: 0,
    decorPulseMinOpacity: .46,
    decorPulseMaxOpacity: 1,
    decorPulseCurve: .9,
    lineLength: 31,
    lineTopWidth: 9.2,
    lineBottomWidth: 5.2,
    leftOuterX: 57.5,
    leftOuterY: 45.5,
    leftOuterAngle: -43.5,
    leftInnerX: 79,
    leftInnerY: 30.5,
    leftInnerAngle: -21,
    rightInnerX: 310,
    rightInnerY: 35.5,
    rightInnerAngle: 17,
    rightOuterX: 332,
    rightOuterY: 50,
    rightOuterAngle: 45.5,
    chestErrorX: 187,
    chestErrorY: 316,
    chestErrorScale: 1.08,
    chestErrorScaleY: .94,
    chestErrorLetterSpacing: 5,
    chestErrorRotate: 0,
    leftHandX: -50,
    leftHandY: 39.5,
    leftHandRotate: 0,
    leftHandScale: 1.12,
    rightHandX: 50,
    rightHandY: 39.5,
    rightHandRotate: 0,
    rightHandScale: 1.12,
    leftRoundness: .86,
    rightRoundness: .86,
    leftSx: 145, leftSy: 250,
    leftRx: 132, leftRy: 230,
    leftEx: 113, leftEy: 210,
    leftWx: 93, leftWy: 184,
    leftTx: 95, leftTy: 154,
    rightSx: 229, rightSy: 250,
    rightRx: 242, rightRy: 230,
    rightEx: 261, rightEy: 210,
    rightWx: 281, rightWy: 184,
    rightTx: 279, rightTy: 154
  };

  const state = {
    ...DEFAULTS,
    showReference: false,
    showOriginalHands: false,
    showBones: false,
    bodyTransparent: false,
    darkStage: false,
    applyErrorFace: true,
    applyFaceLook: true,
    playWobble: true,
    decorEnabled: true,
    panicLinesEnabled: true,
    chestErrorEnabled: true,
    decorPulseEnabled: true
  };
  const baseTransforms = {};
  let baseSvg = document.currentScript && document.currentScript.ownerSVGElement;
  let loopPhase = 0;
  let faceTargetYaw = -state.wobbleAngle;
  let loopStartTime = performance.now();
  let lastTickTime = 0;
  let rafId = null;
  let paused = false;

  if (!baseSvg) return;
  rememberBaseTransforms(baseSvg);
  setPhase(0);

  const reduceMotion = window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  if (!reduceMotion) play();

  window.__cloudlingErrorLoop = { play, pause, setPhase, snapshot };
  window.__cloudlingSetErrorPhase = setPhase;
  window.__clawdSetLowPowerPaused = (value) => {
    paused = Boolean(value);
    if (!paused && !reduceMotion) play();
  };

  function play() {
    paused = false;
    if (rafId !== null) return;
    loopStartTime = performance.now() - loopPhase / Math.max(state.wobbleSpeed, .001) * state.wobbleSeconds * 1000;
    lastTickTime = 0;
    rafId = requestAnimationFrame(tick);
  }

  function pause() {
    paused = true;
    if (rafId !== null) {
      cancelAnimationFrame(rafId);
      rafId = null;
    }
  }

  function tick(now) {
    rafId = null;
    if (paused) return;
    const dt = lastTickTime ? now - lastTickTime : 16.7;
    lastTickTime = now;
    const phase = (now - loopStartTime) / (state.wobbleSeconds * 1000) * state.wobbleSpeed;
    applyFrame(phase, false, dt);
    rafId = requestAnimationFrame(tick);
  }

  function setPhase(phase) {
    const normalized = ((Number(phase) || 0) % 1 + 1) % 1;
    loopPhase = normalized;
    faceTargetYaw = pingPongWave(loopPhase) * state.wobbleAngle;
    state.faceYaw = faceTargetYaw;
    applyFrame(loopPhase, true, 16.7);
    loopStartTime = performance.now() - loopPhase / Math.max(state.wobbleSpeed, .001) * state.wobbleSeconds * 1000;
    lastTickTime = 0;
  }

  function applyFrame(phase, exact, dt) {
    loopPhase = ((phase % 1) + 1) % 1;
    faceTargetYaw = pingPongWave(loopPhase) * state.wobbleAngle;
    state.faceYaw = exact
      ? faceTargetYaw
      : followValue(state.faceYaw, faceTargetYaw, dt, state.faceSmoothing * 1000);
    applyFaceLook();
    applyMotionPose(loopPhase);
    applyDecorPose();
  }

  function snapshot() {
    return {
      mode: "error-loop-v1",
      phase: Number(fmt(loopPhase)),
      faceYaw: Number(fmt(state.faceYaw)),
      faceTargetYaw: Number(fmt(faceTargetYaw)),
      decorOpacity: Number(fmt(decorPulseOpacity()))
    };
  }

  function rememberBaseTransforms(svg) {
    for (const id of [
      "tail",
      "body-layer",
      "tie",
      "error-tie-blade-motion",
      "ears-layer",
      "head-layer",
      "head-tufts",
      "face-layer",
      "sunglasses",
      "error-look-blush-clip-wrapper",
      "error-look-blush-transform"
    ]) {
      const node = svg.querySelector(`#${id}`);
      if (node) {
        if (["tail", "body-layer", "tie", "error-tie-blade-motion"].includes(id)) setStableTransformOrigin(node);
        baseTransforms[id] = node.getAttribute("transform") || "";
      }
    }
  }

function setStableTransformOrigin(node) {
    node.style.transformBox = "view-box";
    node.style.transformOrigin = "0px 0px";
  }

function applyFaceLook() {
    const cheek = cheekPath();
    const active = headLookActive();
    const elem = elementOffsets();
    const ears = earState();

    setSvgAttr("head-cap-fill", "d", headCapPath());
    setSvgAttr("cheek-muzzle-fill", "d", cheek);
    setSvgAttr("error-look-blush-clip-path", "d", cheek);
    setSvgAttr("left-cheek-crease", "d", creasePath("left"));
    setSvgAttr("right-cheek-crease", "d", creasePath("right"));
    setSvgAttr("left-cheek-crease", "stroke-width", active ? "2.6" : "3");
    setSvgAttr("right-cheek-crease", "stroke-width", active ? "2.6" : "3");

    setLayerTransform("head-layer", "");
    setLayerTransform("face-layer", active ? facePlaneTransform(true) : "");
    setLayerTransform("error-look-blush-clip-wrapper", "");
    setElementTransform("error-look-blush-transform", active ? blushPlaneTransform() : "");
    setLayerTransform("ears-layer", "");
    setLayerTransform("head-tufts", active ? tuftLookTransform() : "");
    setElementTransform("sunglasses", "");

    setSvgAttr("left-ear", "transform", active ? translate(ears.left.x, ears.left.y) : "");
    setSvgAttr("right-ear", "transform", active ? translate(ears.right.x, ears.right.y) : "");
    setSvgAttr("left-ear-outer", "r", fmt(lerp(34, 37.4, ears.left.grow)));
    setSvgAttr("left-ear-inner", "r", fmt(lerp(18, 19.8, ears.left.grow)));
    setSvgAttr("right-ear-outer", "r", fmt(lerp(34, 37.4, ears.right.grow)));
    setSvgAttr("right-ear-inner", "r", fmt(lerp(18, 19.8, ears.right.grow)));

    setSvgAttr("left-eye", "transform", centeredTransform({ x: 138, y: 157 }, elem.leftEye.dx, elem.leftEye.dy));
    setSvgAttr("right-eye", "transform", centeredTransform({ x: 237, y: 157 }, elem.rightEye.dx, elem.rightEye.dy));
    setSvgAttr("left-blush", "transform", centeredTransform({ x: 92, y: 185 }, elem.leftBlush.dx, elem.leftBlush.dy, elem.leftBlush.sx, elem.leftBlush.sy));
    setSvgAttr("right-blush", "transform", centeredTransform({ x: 281, y: 185 }, elem.rightBlush.dx, elem.rightBlush.dy, elem.rightBlush.sx, elem.rightBlush.sy));
    setSvgAttr("nose-mouth", "transform", "");
  }

function setSvgAttr(id, name, value) {
    const node = baseSvg?.querySelector(`#${id}`);
    if (!node) return;
    if (value === null || value === undefined || value === "") node.removeAttribute(name);
    else node.setAttribute(name, String(value));
  }

function setLayerTransform(id, extraTransform) {
    const node = baseSvg?.querySelector(`#${id}`);
    if (!node) return;
    const transform = [baseTransforms[id] || "", extraTransform].filter(Boolean).join(" ");
    if (transform) node.setAttribute("transform", transform);
    else node.removeAttribute("transform");
  }

function setElementTransform(id, extraTransform) {
    setLayerTransform(id, extraTransform);
  }

function applyMotionPose(phase = 0) {
    if (!baseSvg) return;
    const pose = motionPose(phase);

    setLayerTransform("body-layer", pose.bodyTransform);
    setLayerTransform("tail", pose.tailTransform);
    setLayerTransform("tie", pose.tieFollowTransform);
    setElementTransform("error-tie-blade-motion", pose.tieBladeTransform);
    setDirectTransform("error-left-hold-head-hand", pose.leftHandTransform);
    setDirectTransform("error-right-hold-head-hand", pose.rightHandTransform);
  }

function motionPose(phase) {
    const theta = phase * Math.PI * 2;
    const manualWave = state.wobbleAngle > .001 ? clamp(state.faceYaw / state.wobbleAngle, -1, 1) : 0;
    const renderedWave = state.wobbleAngle > .001 ? clamp(state.faceYaw / state.wobbleAngle, -1, 1) : 0;
    const faceWave = state.playWobble ? renderedWave : manualWave;
    const bodyWave = -faceWave;
    const pressure = Math.abs(faceWave);

    const bodyDx = state.bodyMotionEnabled ? bodyWave * state.bodyFollowX : 0;
    const bodyDy = state.bodyMotionEnabled ? pressure * state.bodySink : 0;
    const bodyRot = state.bodyMotionEnabled ? bodyWave * state.bodyLean : 0;
    const squash = state.bodyMotionEnabled ? pressure * state.bodySquash : 0;

    const tieBaseWave = state.playWobble ? -pingPongWave(phase - state.tieLag) : -faceWave;
    const tieFlutterWave = state.playWobble ? Math.sin(theta * 2.35 + .4) * (.35 + pressure * .65) : 0;
    const tieAngle = state.tieMotionEnabled ? tieBaseWave * state.tieSwing + tieFlutterWave * state.tieFlutter : 0;

    const handBaseWave = state.playWobble ? faceWave : manualWave;
    const handTrembleWave = state.playWobble ? Math.sin(theta * 2 + .45) : 0;
    const handAngle = state.handMotionEnabled
      ? handBaseWave * state.handRootSwing + handTrembleWave * state.handTremble
      : 0;

    return {
      bodyTransform: state.bodyMotionEnabled ? bodyPoseTransform(bodyDx, bodyDy, bodyRot, squash) : "",
      tailTransform: state.bodyMotionEnabled ? tailPoseTransform(bodyDx, bodyDy, bodyRot) : "",
      tieFollowTransform: state.bodyMotionEnabled ? translate(bodyDx * .74, bodyDy * .82) : "",
      tieBladeTransform: state.tieMotionEnabled ? tieBladeTransform(tieAngle, pressure) : "",
      leftHandTransform: state.handMotionEnabled ? handRootSwingTransform("left", handAngle) : "",
      rightHandTransform: state.handMotionEnabled ? handRootSwingTransform("right", handAngle) : ""
    };
  }

function applyDecorPose() {
    if (!baseSvg || !state.decorEnabled) return;
    const opacity = fmt(decorPulseOpacity());
    setSvgAttr("error-panic-lines", "opacity", opacity);
    setSvgAttr("error-chest-text", "opacity", opacity);
  }

function decorPulseOpacity() {
    if (!state.decorPulseEnabled) return 1;
    const min = Math.min(state.decorPulseMinOpacity, state.decorPulseMaxOpacity);
    const max = Math.max(state.decorPulseMinOpacity, state.decorPulseMaxOpacity);
    const faceWave = state.wobbleAngle > .001 ? clamp(state.faceYaw / state.wobbleAngle, -1, 1) : 0;
    const pressure = Math.abs(faceWave);
    const shaped = smooth01(Math.pow(pressure, Math.max(.05, state.decorPulseCurve)));
    return lerp(min, max, shaped);
  }

function pingPongWave(phase) {
    const p = ((phase % 1) + 1) % 1;
    if (p < .5) return -1 + p * 4;
    return 3 - p * 4;
  }

function bodyPoseTransform(dx, dy, rotateDeg, squash) {
    if (nearZero(dx) && nearZero(dy) && nearZero(rotateDeg) && nearZero(squash)) return "";
    const sx = 1 + squash * .58;
    const sy = 1 - squash;
    return [
      translate(dx, dy),
      `rotate(${fmt(rotateDeg)} ${BODY_ORIGIN.x} ${BODY_ORIGIN.y})`,
      `translate(${BODY_ORIGIN.x} ${BODY_ORIGIN.y})`,
      `scale(${fmt(sx)} ${fmt(sy)})`,
      `translate(${-BODY_ORIGIN.x} ${-BODY_ORIGIN.y})`
    ].join(" ");
  }

function tailPoseTransform(dx, dy, rotateDeg) {
    if (nearZero(dx) && nearZero(dy) && nearZero(rotateDeg)) return "";
    return [
      translate(dx * .34, dy * .26),
      `rotate(${fmt(rotateDeg * .18)} ${TAIL_ORIGIN.x} ${TAIL_ORIGIN.y})`
    ].join(" ");
  }

function tieBladeTransform(angle, pressure) {
    if (nearZero(angle) && nearZero(pressure)) return "";
    const stretchY = 1 + pressure * .018;
    return [
      `rotate(${fmt(angle)} ${TIE_BLADE_PIVOT.x} ${TIE_BLADE_PIVOT.y})`,
      `translate(${fmt(angle * .018)} ${fmt(pressure * .65)})`,
      `translate(${TIE_BLADE_PIVOT.x} ${TIE_BLADE_PIVOT.y})`,
      `scale(1 ${fmt(stretchY)})`,
      `translate(${-TIE_BLADE_PIVOT.x} ${-TIE_BLADE_PIVOT.y})`
    ].join(" ");
  }

function handRootSwingTransform(side, angle) {
    if (nearZero(angle)) return "";
    const sign = side === "left" ? 1 : -1;
    const pivot = point(side, "S");
    return `rotate(${fmt(sign * angle)} ${fmt(pivot.x)} ${fmt(pivot.y)})`;
  }

function setDirectTransform(id, transform) {
    const node = baseSvg?.querySelector(`#${id}`);
    if (!node) return;
    if (transform) node.setAttribute("transform", transform);
    else node.removeAttribute("transform");
  }

function lookYaw() {
    return state.applyFaceLook ? state.faceYaw : 0;
  }

function lookPitch() {
    return state.applyFaceLook ? state.facePitch : 0;
  }

function headLookActive() {
    return Math.abs(lookYaw()) > .001 || Math.abs(lookPitch()) > .001;
  }

function axisT(value) {
    return smooth01(Math.abs(value) / 100);
  }

function yawAxisT(value) {
    const t = clamp(Math.abs(value) / 100, 0, 1);
    return state.playWobble ? t : smooth01(t);
  }

function diagonalFactor() {
    return Math.abs(lookYaw()) / 100 * Math.abs(lookPitch()) / 100;
  }

function trimmed(value, trimScale = 1) {
    const trim = 1 - diagonalFactor() * 15 / 100 * trimScale;
    return value * trim;
  }

function smoothRange(start, end, value) {
    return smooth01(clamp((value - start) / (end - start), 0, 1));
  }

function mixPoint(a, b, t) {
    return { x: lerp(a.x, b.x, t), y: lerp(a.y, b.y, t) };
  }

function interpolateNumberString(from, to, t) {
    const a = numbers(from);
    const b = numbers(to);
    let index = 0;
    if (!from || !to || a.length !== b.length) return t < 1 ? from : to;
    return from.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, () => {
      const val = lerp(a[index], b[index] !== undefined ? b[index] : a[index - 1], t);
      index += 1;
      return fmt(val);
    });
  }

function transformTopPoint(point, dir) {
    const axisX = dir < 0 ? 125 : 249;
    const axisTravel = (axisX - VIEW_W / 2) * .75;
    const localX = point.x - axisX;
    const next = { x: axisTravel + axisX + localX, y: point.y };
    const a = RAW_ANCHORS.A || { x: 65 };
    const g = RAW_ANCHORS.G || { x: 309 };
    const weightT = clamp((point.x - a.x) / (g.x - a.x), 0, 1);
    const weight = Math.pow(Math.sin(Math.PI * weightT), .9);
    return {
      x: point.x + (next.x - point.x) * weight,
      y: point.y
    };
  }

function catmullPath(points, tension = .72, sharpness = .34) {
    const segs = [`M${fmt(points[0].x)} ${fmt(points[0].y)}`];
    for (let i = 0; i < points.length - 1; i++) {
      const p0 = points[Math.max(0, i - 1)];
      const p1 = points[i];
      const p2 = points[i + 1];
      const p3 = points[Math.min(points.length - 1, i + 2)];
      const nearBridge = ["C", "D", "E"].includes(p1.id) || ["C", "D", "E"].includes(p2.id);
      const localTension = tension * (nearBridge ? (1 - sharpness * .42) : 1);
      const c1 = {
        x: p1.x + (p2.x - p0.x) * localTension / 6,
        y: p1.y + (p2.y - p0.y) * localTension / 6
      };
      const c2 = {
        x: p2.x - (p3.x - p1.x) * localTension / 6,
        y: p2.y - (p3.y - p1.y) * localTension / 6
      };
      segs.push(`C${fmt(c1.x)} ${fmt(c1.y)} ${fmt(c2.x)} ${fmt(c2.y)} ${fmt(p2.x)} ${fmt(p2.y)}`);
    }
    return segs.join(" ");
  }

function continuousYawFaceBasePath() {
    const top = TOP_CHAIN.map((id) => {
      const point = RAW_ANCHORS[id];
      return { id, x: point.x, y: point.y };
    });
    const tail = FRONT_TAIL.map((seg) => `C${fmt(seg[0])} ${fmt(seg[1])} ${fmt(seg[2])} ${fmt(seg[3])} ${fmt(seg[4])} ${fmt(seg[5])}`).join(" ");
    return `${catmullPath(top)} ${tail}Z`;
  }

function yawFacePath() {
    const yaw = lookYaw();
    const dir = Math.sign(yaw);
    const t = yawAxisT(yaw);
    if (TOP_CHAIN.some((id) => !RAW_ANCHORS[id])) return FACE_BASE.cheekD;
    if (!dir || t <= .001) {
      const keepContinuous = state.playWobble || Math.abs(lookPitch()) > .001;
      return keepContinuous ? continuousYawFaceBasePath() : FACE_BASE.cheekD;
    }
    const top = TOP_CHAIN.map((id) => {
      const start = RAW_ANCHORS[id];
      const end = transformTopPoint(start, dir);
      const mixed = mixPoint(start, end, t);
      return { id, x: mixed.x, y: mixed.y };
    });
    const sideTail = dir < 0 ? LEFT_TAIL : RIGHT_TAIL;
    const tail = FRONT_TAIL.map((seg, index) => {
      const mixed = seg.map((value, numberIndex) => lerp(value, sideTail[index][numberIndex], t));
      return `C${fmt(mixed[0])} ${fmt(mixed[1])} ${fmt(mixed[2])} ${fmt(mixed[3])} ${fmt(mixed[4])} ${fmt(mixed[5])}`;
    }).join(" ");
    return `${catmullPath(top)} ${tail}Z`;
  }

function faceLowerEffect() {
    const pitch = lookPitch();
    if (pitch <= 0) return 0;
    return axisT(pitch) * lerp(.45, 1, yawAxisT(lookYaw()));
  }

function faceLowerWrappedPoint(point) {
    const effect = faceLowerEffect();
    if (effect <= .001) return point;
    const lower = smoothRange(238, 263, point.y);
    if (lower <= .001) return point;
    const side = Math.sign(point.x - 187);
    return {
      x: point.x + side * 6 * effect * lower * .3,
      y: point.y + 12 * effect * lower
    };
  }

function faceLowerWrappedPath(path) {
    return transformPathPairs(path, faceLowerWrappedPoint);
  }

function pitchDeltaY(y) {
    const pitch = lookPitch();
    if (pitch === 0) return 0;
    const sign = Math.sign(pitch);
    const t = axisT(pitch);
    const lowerWeight = clamp((y - 166) / 92, 0, 1);
    if (sign < 0) return lerp(PITCH_UP.axis, PITCH_UP.lower, lowerWeight) * t;
    return lerp(PITCH_DOWN.axis, PITCH_DOWN.lower, lowerWeight) * t;
  }

function warpPathForPitch(path) {
    let index = 0;
    return path.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, (value) => {
      const n = Number(value);
      const next = index % 2 === 1 ? n + pitchDeltaY(n) : n;
      index += 1;
      return fmt(next);
    });
  }

function cheekPath() {
    return faceLowerWrappedPath(warpPathForPitch(yawFacePath()));
  }

function headCapPath() {
    const yaw = lookYaw();
    const pitch = lookPitch();
    const yawT = yawAxisT(yaw);
    const dir = Math.sign(yaw);
    const yawTarget = dir > 0 ? RIGHT_HEAD_CAP_D : LEFT_HEAD_CAP_D;
    const yawPath = dir ? interpolateNumberString(FACE_BASE.headCapD, yawTarget, yawT) : FACE_BASE.headCapD;
    let index = 0;
    return yawPath.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, (value) => {
      const n = Number(value);
      if (index % 2 === 0) {
        index += 1;
        return fmt(n);
      }
      const topWeight = clamp((120 - n) / 80, 0, 1);
      const sideWeight = clamp((n - 120) / 70, 0, 1);
      const sign = Math.sign(pitch);
      const t = axisT(pitch);
      const delta = sign < 0
        ? (2 * topWeight - 5.61 * sideWeight) * t
        : (-1.87 * topWeight + 7.28 * sideWeight) * t;
      index += 1;
      return fmt(n + delta);
    });
  }

function creasePath(side) {
    const isLeft = side === "left";
    const base = FACE_BASE[isLeft ? "leftCreaseD" : "rightCreaseD"];
    const sideSign = isLeft ? 1 : -1;
    const startX = isLeft ? 62 : 312;
    const baseLength = 38;
    const yawT = yawAxisT(lookYaw());
    const yawPull = Math.sign(lookYaw()) * yawT;
    const pitchT = axisT(lookPitch());
    return transformPathPairs(base, (point) => {
      const along = isLeft
        ? clamp((point.x - 62) / baseLength, 0, 1)
        : clamp((312 - point.x) / baseLength, 0, 1);
      const next = {
        x: startX + (point.x - startX),
        y: point.y
      };
      next.x += yawPull * (isLeft ? 1 : -1) * lerp(3, 6, along);
      next.x += sideSign * lerp(1.8, 2.4, along) * pitchT;
      next.y += pitchDeltaY(point.y);
      return faceLowerWrappedPoint(next);
    });
  }

function facePlaneTransform(withPitchScale) {
    const yaw = lookYaw();
    const pitch = lookPitch();
    const dir = Math.sign(yaw);
    const yawT = yawAxisT(yaw);
    const axis = 187 + dir * 62 * yawT;
    const dx = dir * 46.5 * yawT;
    const pitchSign = Math.sign(pitch);
    const pitchT = axisT(pitch);
    const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
    const dy = trimmed(pitchData.faceDy * pitchT, .45);
    const sy = withPitchScale ? lerp(1, pitchData.faceSy, pitchT) : 1;
    return `translate(${fmt(dx)} ${fmt(dy)}) translate(${fmt(axis)} 172) skewX(0) scale(1 ${fmt(sy)}) translate(${fmt(-axis)} -172)`;
  }

function blushPlaneTransform() {
    const yaw = lookYaw();
    const pitch = lookPitch();
    const dir = Math.sign(yaw);
    const yawT = yawAxisT(yaw);
    const axis = 187 + dir * 62 * yawT;
    const dx = dir * 46.5 * yawT;
    const pitchSign = Math.sign(pitch);
    const pitchT = axisT(pitch);
    const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
    const dy = trimmed(pitchData.blushDy * pitchT, .35);
    return `translate(${fmt(dx)} ${fmt(dy)}) translate(${fmt(axis)} 172) skewX(0) scale(1 1) translate(${fmt(-axis)} -172)`;
  }

function centeredTransform(origin, dx, dy, sx = 1, sy = 1) {
    if (Math.abs(dx) < 1e-6 && Math.abs(dy) < 1e-6 && Math.abs(sx - 1) < 1e-6 && Math.abs(sy - 1) < 1e-6) return "";
    return `translate(${fmt(origin.x + dx)} ${fmt(origin.y + dy)}) scale(${fmt(sx)} ${fmt(sy)}) translate(${fmt(-origin.x)} ${fmt(-origin.y)})`;
  }

function elementOffsets() {
    const yaw = lookYaw();
    const pitch = lookPitch();
    const dir = Math.sign(yaw);
    const yawT = yawAxisT(yaw);
    const pitchSign = Math.sign(pitch);
    const pitchT = axisT(pitch);
    const pitchUp = pitchSign < 0;
    const pitchEye = pitchUp ? -.56 * pitchT : 0;
    const pitchBlushDx = pitchUp ? 3.5 * pitchT : -1.8 * pitchT;
    const yawLeftEye = dir < 0 ? -2 * yawT : 0;
    const yawRightEye = dir > 0 ? 2 * yawT : 0;
    const leftBlushYaw = dir < 0
      ? { dx: 6.5 * yawT, dy: 0, sx: 1, sy: 1 }
      : { dx: -24 * yawT, dy: 20.5 * yawT, sx: lerp(1, 1.09, yawT), sy: lerp(1, 1.1, yawT) };
    const rightBlushYaw = dir < 0
      ? { dx: 25 * yawT, dy: 20.5 * yawT, sx: lerp(1, 1.09, yawT), sy: lerp(1, 1.1, yawT) }
      : { dx: -5.5 * yawT, dy: 0, sx: 1, sy: 1 };
    return {
      leftEye: { dx: yawLeftEye, dy: pitchEye },
      rightEye: { dx: yawRightEye, dy: pitchEye },
      leftBlush: {
        dx: leftBlushYaw.dx + pitchBlushDx,
        dy: leftBlushYaw.dy,
        sx: leftBlushYaw.sx,
        sy: leftBlushYaw.sy
      },
      rightBlush: {
        dx: rightBlushYaw.dx - pitchBlushDx,
        dy: rightBlushYaw.dy,
        sx: rightBlushYaw.sx,
        sy: rightBlushYaw.sy
      }
    };
  }

function earState() {
    const yaw = lookYaw();
    const pitch = lookPitch();
    const dir = Math.sign(yaw);
    const yawT = yawAxisT(yaw);
    const pitchSign = Math.sign(pitch);
    const pitchT = axisT(pitch);
    const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
    const pitchDy = pitchData.earDy * pitchT;
    const left = { x: 0, y: pitchDy, grow: 0 };
    const right = { x: 0, y: pitchDy, grow: 0 };
    if (dir < 0) {
      left.x += -3.5 * yawT;
      left.y += 3.5 * yawT;
      right.grow = smoothRange(.12, 1, yawT);
    } else if (dir > 0) {
      right.x += -9.5 * yawT;
      right.y += 3.5 * yawT;
      left.grow = smoothRange(.12, 1, yawT);
    }
    return { left, right };
  }

function tuftLookTransform() {
    const yaw = lookYaw();
    const pitch = lookPitch();
    const dir = Math.sign(yaw);
    const yawT = yawAxisT(yaw);
    const pitchSign = Math.sign(pitch);
    const pitchT = axisT(pitch);
    const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
    const yawDx = dir < 0 ? -21.7 * yawT : dir > 0 ? -10.3 * yawT : 0;
    const pitchDy = pitchData.tuftDy * pitchT;
    return translate(yawDx, pitchDy);
  }

function point(side, key) {
    const raw = { x: state[`${side}${key}x`], y: state[`${side}${key}y`] };
    const pivot = { x: state[`${side}Rx`], y: state[`${side}Ry`] };
    const scaled = {
      x: pivot.x + (raw.x - pivot.x) * state[`${side}HandScale`],
      y: pivot.y + (raw.y - pivot.y) * state[`${side}HandScale`]
    };
    const rotated = rotateAround(scaled, pivot, state[`${side}HandRotate`] * Math.PI / 180);
    return {
      x: rotated.x + state[`${side}HandX`],
      y: rotated.y + state[`${side}HandY`]
    };
  }

function rotateAround(point, center, angle) {
    const cos = Math.cos(angle);
    const sin = Math.sin(angle);
    const dx = point.x - center.x;
    const dy = point.y - center.y;
    return {
      x: center.x + dx * cos - dy * sin,
      y: center.y + dx * sin + dy * cos
    };
  }

function lerp(a, b, t) { return a + (b - a) * t; }

function clamp(v, min, max) { return Math.max(min, Math.min(max, v)); }

function nearZero(value) { return Math.abs(value) < 1e-6; }

function numbers(value) {
    return (String(value).match(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi) || []).map(Number);
  }

function transformPathPairs(path, fn) {
    const values = numbers(path);
    const output = [];
    for (let i = 0; i < values.length; i += 2) {
      const point = fn({ x: values[i], y: values[i + 1] });
      output.push(point.x, point.y);
    }
    let index = 0;
    return path.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, () => fmt(output[index++]));
  }

function translate(x, y) {
    return Math.abs(x) < 1e-6 && Math.abs(y) < 1e-6 ? "" : `translate(${fmt(x)} ${fmt(y)})`;
  }

function smooth01(v) {
    const t = clamp(v, 0, 1);
    return t * t * (3 - 2 * t);
  }

function fmt(value) {
    return Number(value).toFixed(3).replace(/\.?0+$/, "");
  }

function followValue(current, target, dtMs, smoothingMs) {
    if (smoothingMs <= 0 || !Number.isFinite(current)) return target;
    const alpha = 1 - Math.exp(-dtMs / Math.max(1, smoothingMs));
    return current + (target - current) * clamp(alpha, 0, 1);
  }
})();
